import{_ as t,c as e,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"よくある質問とベストプラクティス | AI App Factory チュートリアル","description":"FAQ セクションでは、AI App Factory の使用中に遭遇する一般的な問題の解決策とベストプラクティスをまとめています。トラブルシューティングを迅速に行い、開発効率を向上させるのに役立ちます。","frontmatter":{"title":"よくある質問とベストプラクティス | AI App Factory チュートリアル","sidebarTitle":"よくある質問","subtitle":"よくある質問とベストプラクティス","description":"FAQ セクションでは、AI App Factory の使用中に遭遇する一般的な問題の解決策とベストプラクティスをまとめています。トラブルシューティングを迅速に行い、開発効率を向上させるのに役立ちます。","order":190},"headers":[],"relativePath":"ja/hyz1992/agent-app-factory/faq/index.md","filePath":"ja/hyz1992/agent-app-factory/faq/index.md"}'),i={name:"ja/hyz1992/agent-app-factory/faq/index.md"};function l(d,a,n,s,p,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="よくある質問とベストプラクティス" tabindex="-1">よくある質問とベストプラクティス <a class="header-anchor" href="#よくある質問とベストプラクティス" aria-label="Permalink to &quot;よくある質問とベストプラクティス&quot;">​</a></h1><p>FAQ セクションでは、AI App Factory の使用中に遭遇する一般的な問題の解決策とベストプラクティスをまとめています。トラブルシューティングを迅速に行い、開発効率を向上させるのに役立ちます。</p><h2 id="サブページナビゲーション" tabindex="-1">サブページナビゲーション <a class="header-anchor" href="#サブページナビゲーション" aria-label="Permalink to &quot;サブページナビゲーション&quot;">​</a></h2><table tabindex="0"><thead><tr><th>コース</th><th>説明</th></tr></thead><tbody><tr><td><strong><a href="./../troubleshooting/">よくある質問とトラブルシューティング</a></strong></td><td>初期化、実行、デプロイ中に遭遇する一般的な問題を解決</td></tr><tr><td><strong><a href="./../best-practices/">ベストプラクティス</a></strong></td><td>明確なプロダクト記述の提供、チェックポイントの活用、スコープの制御、段階的なイテレーションなどのテクニックを学習</td></tr></tbody></table><h2 id="学習パスの推奨" tabindex="-1">学習パスの推奨 <a class="header-anchor" href="#学習パスの推奨" aria-label="Permalink to &quot;学習パスの推奨&quot;">​</a></h2><p>FAQ セクションの内容は必要に応じて参照でき、厳密な順序で学習する必要はありません：</p><ol><li><strong>問題が発生したら参照</strong>：使用中に問題が発生した場合、まず「よくある質問とトラブルシューティング」を確認してください</li><li><strong>効率向上のため必読</strong>：「ベストプラクティス」セクションでは経験と教訓をまとめています。最初のプロジェクトを完了した後に読むことをお勧めします。以降のプロジェクトの開発効率が大幅に向上します</li></ol><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推奨される事前学習</p><p>FAQ セクションを読む前に、以下の内容を完了することをお勧めします：</p><ul><li>✅ <strong>start</strong> セクション：プロジェクトの初期化を完了し、完全なパイプラインを実行済みであること</li><li>✅ <strong>platforms</strong> セクション：少なくとも 1 つの AI アシスタント（Claude Code または OpenCode）を設定済みであること</li></ul></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>FAQ の学習を完了したら、以下のことができます：</p><ol><li><p>技術の詳細を深く理解する：</p><ul><li><a href="./../../appendix/cli-commands/">CLI コマンドリファレンス</a> - 完全なコマンドリストとパラメータを確認</li><li><a href="./../../appendix/directory-structure/">ディレクトリ構造の詳細</a> - プロジェクト構造とファイルの用途を理解</li><li><a href="./../../appendix/code-standards/">コード規約</a> - 生成されたコードが従うべき規約を理解</li></ul></li><li><p>実践を開始する：</p><ul><li>ベストプラクティスを使用してプロジェクトの説明を最適化する</li><li>より複雑なプロダクトのアイデアを試す</li><li>7 段階パイプラインの各詳細を探索する</li></ul></li></ol>',12)])])}const f=t(i,[["render",l]]);export{u as __pageData,f as default};
